SELECT * FROM activity_application
WHERE activity_id = #{activityId} AND volunteer_id = #{volunteerId}
LIMIT 1

SELECT volunteer_id FROM activity_application
WHERE activity_id = #{activityId}
  AND (status = '待参与' OR status = '已通过')

